import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { 
  LayoutDashboard, List, Home, 
  CreditCard, Wallet, LogOut, User, 
  ArrowUpCircle, ArrowDownCircle, Layers,
  Target, PlusCircle, PieChart 
} from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Sidebar.css';

const Sidebar = () => {
  const location = useLocation();
  const [perfil, setPerfil] = useState({ tipo: 'comum' });
  const [modalLogout, setModalLogout] = useState({ isOpen: false });

  const isActive = (path) => location.pathname.toLowerCase() === path.toLowerCase();

  // Verifica se o usuário tem permissões elevadas (Proprietário ou Administrador)
  const temAcessoAdmin = perfil.tipo === 'proprietario' || perfil.tipo === 'administrador';

  useEffect(() => {
    obterPerfil();
  }, []);

  async function obterPerfil() {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        const { data, error } = await supabase
          .from('profiles')
          .select('tipo_usuario')
          .eq('id', user.id)
          .single();
        
        if (error) throw error;

        const isMaster = user.email === 'gleidson.fig@gmail.com';
        // Se for o e-mail master, sempre será proprietário. Caso contrário, pega do banco.
        const tipoFinal = isMaster ? 'proprietario' : (data?.tipo_usuario || 'comum');
        
        setPerfil({ tipo: tipoFinal });
      }
    } catch (error) {
      console.error("Erro ao carregar perfil na Sidebar:", error.message);
    }
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  return (
    <>
      <aside className="sidebar-container">
        <div className="sidebar-logo">
          <Wallet size={28} fill="#4361ee30" />
          <span>Finanças</span>
        </div>

        <nav className="sidebar-nav-list">
          <Link to="/" className={`sidebar-nav-item ${isActive('/') ? 'active' : ''}`}>
            <Home size={20} />
            <span>Início</span>
          </Link>

          {/* SEÇÃO LIBERADA PARA ADMIN E PROPRIETÁRIO */}
          {temAcessoAdmin && (
            <>
              <Link to="/lancamento" className={`sidebar-nav-item ${isActive('/lancamento') ? 'active' : ''}`}>
                <PlusCircle size={20} />
                <span>Lançar</span>
              </Link>
              
              <Link to="/proventos" className={`sidebar-nav-item ${isActive('/proventos') ? 'active' : ''}`}>
                <ArrowUpCircle size={20} />
                <span>Entradas</span>
              </Link>

              <Link to="/despesas" className={`sidebar-nav-item ${isActive('/despesas') ? 'active' : ''}`}>
                <ArrowDownCircle size={20} />
                <span>Saídas</span>
              </Link>

              <Link to="/categorias" className={`sidebar-nav-item ${isActive('/categorias') ? 'active' : ''}`}>
                <Layers size={20} />
                <span>Categorias</span>
              </Link>

              <div className="sidebar-divider-mini" style={{ margin: '10px 15px', borderTop: '1px solid #f1f5f9' }}></div>

              {/* SEÇÃO DE PLANEJAMENTO */}
              <Link to="/metas" className={`sidebar-nav-item ${isActive('/metas') ? 'active' : ''}`}>
                <Target size={20} />
                <span>Metas</span>
              </Link>

              <Link to="/orcamento" className={`sidebar-nav-item ${isActive('/orcamento') ? 'active' : ''}`}>
                <PieChart size={20} />
                <span>Orçamento</span>
              </Link>

              <Link to="/cartoes" className={`sidebar-nav-item ${isActive('/cartoes') ? 'active' : ''}`}>
                <CreditCard size={20} />
                <span>Cartões</span>
              </Link>
            </>
          )}

          <div className="sidebar-divider-mini" style={{ margin: '10px 15px', borderTop: '1px solid #f1f5f9' }}></div>

          <Link to="/listagem" className={`sidebar-nav-item ${isActive('/listagem') ? 'active' : ''}`}>
            <List size={20} />
            <span>Extrato</span>
          </Link>

          <Link to="/dashboard" className={`sidebar-nav-item ${isActive('/dashboard') ? 'active' : ''}`}>
            <LayoutDashboard size={20} />
            <span>Painel</span>
          </Link>

          <Link to="/perfil" className={`sidebar-nav-item ${isActive('/perfil') ? 'active' : ''}`}>
            <User size={20} />
            <span>Perfil</span>
          </Link>

          <div className="sidebar-divider" style={{ margin: '15px 0', borderTop: '1px solid #f1f5f9' }}></div>

          <button 
            type="button"
            onClick={() => setModalLogout({ isOpen: true })} 
            className="sidebar-nav-item sidebar-logout-btn"
            style={{ width: '100%', border: 'none', background: 'none', cursor: 'pointer' }}
          >
            <LogOut size={20} />
            <span>Sair</span>
          </button>
        </nav>
      </aside>

      <ModalFeedback
        isOpen={modalLogout.isOpen}
        type="error"
        title="Encerrar Sessão?"
        message="Você terá que entrar com suas credenciais novamente para acessar o sistema."
        onClose={() => setModalLogout({ isOpen: false })}
        onConfirm={handleLogout}
      />
    </>
  );
};

export default Sidebar;
